    Limit            *modelsDevLimit   `json:"limit,omitempty"`
    Modalities       *modelsDevModalities `json:"modalities,omitempty"`
}

type modelsDevCost struct {
    Input      *float64 `json:"input,omitempty"`
    Output     *float64 `json:"output,omitempty"`
